/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Duplicatas"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &CreCarBanCod.IsEmpty() print printBlockFilterCreCarBanCod EndIf If not &CreCliCod.IsEmpty() print printBlockFilterCreCliCod EndIf If not &CreCliRaz.IsEmpty() print printBlockFilterCreCliRaz EndIf If not &CreVlrSdo.IsEmpty() print printBlockFilterCreVlrSdo EndIf If not &CreFilPgt.IsEmpty() print printBlockFilterCreFilPgt EndIf If not &CreRecPag.IsEmpty() &FilterCreRecPagValueDescription = &CreRecPag.EnumerationDescription()
print printBlockFilterCreRecPag EndIf If not &CreSts.IsEmpty() &FilterCreStsValueDescription = &CreSts.EnumerationDescription()
print printBlockFilterCreSts EndIf If not &CreFrpPgtoTip.IsEmpty() &FilterCreFrpPgtoTipValueDescription = &CreFrpPgtoTip.EnumerationDescription()
print printBlockFilterCreFrpPgtoTip EndIf If not &CreDtaVct.IsEmpty() print printBlockFilterCreDtaVct EndIf If not &CreDtaVct_To.IsEmpty() &CreDtaVct_To_Description = format('%1 (%2)', "Vcto.", "à") print printBlockFilterCreDtaVct_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CRECARNROAUT' &CreCarNroAut1.FromString(&GridStateDynamicFilter.Value) If not &CreCarNroAut1.IsEmpty() &CreCarNroAut = &CreCarNroAut1 print printBlockFilterCreCarNroAut EndIf Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CreDupNro = &CreDupNro1 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector1 = !'CRECARCREDEB' &CreCarCreDeb1.FromString(&GridStateDynamicFilter.Value) If not &CreCarCreDeb1.IsEmpty() &FilterCreCarCreDeb1ValueDescription = '' Do Case Case &CreCarCreDeb1 = 1 &FilterCreCarCreDeb1ValueDescription = "Débito"
Case &CreCarCreDeb1 = 2 &FilterCreCarCreDeb1ValueDescription = "Crédito"
EndCase
&FilterCreCarCreDebValueDescription = &FilterCreCarCreDeb1ValueDescription print printBlockFilterCreCarCreDeb EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CRECARNROAUT' &CreCarNroAut2.FromString(&GridStateDynamicFilter.Value) If not &CreCarNroAut2.IsEmpty() &CreCarNroAut = &CreCarNroAut2 print printBlockFilterCreCarNroAut EndIf Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CreDupNro = &CreDupNro2 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector2 = !'CRECARCREDEB' &CreCarCreDeb2.FromString(&GridStateDynamicFilter.Value) If not &CreCarCreDeb2.IsEmpty() &FilterCreCarCreDeb2ValueDescription = '' Do Case Case &CreCarCreDeb2 = 1 &FilterCreCarCreDeb2ValueDescription = "Débito"
Case &CreCarCreDeb2 = 2 &FilterCreCarCreDeb2ValueDescription = "Crédito"
EndCase
&FilterCreCarCreDebValueDescription = &FilterCreCarCreDeb2ValueDescription print printBlockFilterCreCarCreDeb EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CRECARNROAUT' &CreCarNroAut3.FromString(&GridStateDynamicFilter.Value) If not &CreCarNroAut3.IsEmpty() &CreCarNroAut = &CreCarNroAut3 print printBlockFilterCreCarNroAut EndIf Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CreDupNro = &CreDupNro3 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector3 = !'CRECARCREDEB' &CreCarCreDeb3.FromString(&GridStateDynamicFilter.Value) If not &CreCarCreDeb3.IsEmpty() &FilterCreCarCreDeb3ValueDescription = '' Do Case Case &CreCarCreDeb3 = 1 &FilterCreCarCreDeb3ValueDescription = "Débito"
Case &CreCarCreDeb3 = 2 &FilterCreCarCreDeb3ValueDescription = "Crédito"
EndCase
&FilterCreCarCreDebValueDescription = &FilterCreCarCreDeb3ValueDescription print printBlockFilterCreCarCreDeb EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreRecPag FilCod CreDtaVct when &OrderedBy = 1 order EmpCod CreRecPag FilCod (CreDtaVct) when &OrderedBy = 2 order EmpCod CreRecPag FilCod CreDupNro when &OrderedBy = 3 order EmpCod CreRecPag FilCod CreCliCod when &OrderedBy = 4 order CrePedLctCod when &OrderedBy = 5 AND &OrderedDsc = False order (CrePedLctCod) when &OrderedBy = 5 AND &OrderedDsc = True order CreDupNro when &OrderedBy = 6 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 6 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 7 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 7 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 8 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 8 AND &OrderedDsc = True order CreVlrSdo when &OrderedBy = 9 AND &OrderedDsc = False order (CreVlrSdo) when &OrderedBy = 9 AND &OrderedDsc = True order CreCarBanNom when &OrderedBy = 10 AND &OrderedDsc = False order (CreCarBanNom) when &OrderedBy = 10 AND &OrderedDsc = True order CreCarNroAut when &OrderedBy = 11 AND &OrderedDsc = False order (CreCarNroAut) when &OrderedBy = 11 AND &OrderedDsc = True order CreCarCardNom when &OrderedBy = 12 AND &OrderedDsc = False order (CreCarCardNom) when &OrderedBy = 12 AND &OrderedDsc = True order CreCarTax when &OrderedBy = 13 AND &OrderedDsc = False order (CreCarTax) when &OrderedBy = 13 AND &OrderedDsc = True order CrePedCod when &OrderedBy = 14 AND &OrderedDsc = False order (CrePedCod) when &OrderedBy = 14 AND &OrderedDsc = True order CreVenCod when &OrderedBy = 15 AND &OrderedDsc = False order (CreVenCod) when &OrderedBy = 15 AND &OrderedDsc = True
using DSWWDuplicatasCartao(&CreCarBanCod, &CreCliCod, &CreCliRaz, &CreVlrSdo, &CreFilPgt, &CreRecPag , &CreSts, &CreFrpPgtoTip, &DynamicFiltersSelector1, &CreCarNroAut1, &CreDupNro1, &CreCarCreDeb1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &CreCarNroAut2, &CreDupNro2, &CreCarCreDeb2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &CreCarNroAut3, &CreDupNro3, &CreCarCreDeb3, &CreDtaVct, &CreDtaVct_To) if CreNovCliRaz_Formula.Length() > 30 &CreNovCliRaz = substr(CreNovCliRaz_Formula, 1, 30) + '...' Else &CreNovCliRaz = CreNovCliRaz_Formula EndIf &Bandeira = RetornaNomeBandeira.Udp(EmpCod, CreCarBanCod)
if CreCarCreDeb > 1 &Tipo= 'CRÉDITO' Else &Tipo= 'DÉBITO' Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWDuplicatasCartaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWDuplicatasCartaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWDuplicatasCartaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECARBANCOD" &CreCarBanCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRECLIRAZ" &CreCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFILPGT" &CreFilPgt.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFRPPGTOTIP" &CreFrpPgtoTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportWWDuplicatasCartao","PDF");

